    (_facts as any).lowerperformancewallliningclass;

  if (lowerClassRaw === undefined || lowerClassRaw === null || String(lowerClassRaw).trim() === "") {
    return UNKNOWN("lowerPerformanceLiningClass missing (must be no worse than D-s3,d2)", [
      "lowerPerformanceLiningClass=missing",
      "allowanceAppliedFlag=true",
    ]);
  }

  const ok = isNoWorseThan_D_s3_d2(String(lowerClassRaw));
