    if (typeof v === "number") {
      if (v === 1) return true;
      if (v === 0) return false;
    }
    const s = String(v).trim().toLowerCase();
    if (["true", "yes", "1"].includes(s)) return true;
    if (["false", "no", "0"].includes(s)) return false;
