  if (h <= 18)
    return PASS("No storey exceeds 18m above FRS access level (rule not applicable)", [
      `maxStoreyAboveFRSAccessLevelM=${h}`
    ]);

  const shaft = bool(
    (_facts as any).firefightingShaftProvidedFlag ??
      (_facts as any).firefightingshaftprovidedflag ??
      (_facts as any).firefightingShaftsProvided ??
      (_facts as any).firefightingshaftsprovided
  );

  if (shaft === undefined)
    return UNKNOWN("firefightingShaftProvidedFlag missing (required when >18m)", [
      `maxStoreyAboveFRSAccessLevelM=${h}`
    ]);

  const rawN =
    (_facts as any).numberOfFirefightingShafts ??
    (_facts as any).numberoffirefightingshafts ??
    (_facts as any).firefightingShaftCount ??
    (_facts as any).firefightingshaftcount;

  const n =
    rawN === undefined || rawN === null || rawN === ""
      ? undefined
      : Number(rawN);

  if (n === undefined || Number.isNaN(n))
    return UNKNOWN("numberOfFirefightingShafts missing (required when >18m)", [
      `maxStoreyAboveFRSAccessLevelM=${h}`
    ]);

  const lift = bool(
    (_facts as any).firefightingLiftProvidedFlag ??
      (_facts as any).firefightingliftprovidedflag ??
      (_facts as any).firefightingLiftProvided ??
      (_facts as any).firefightingliftprovided
  );

  if (lift === undefined)
    return UNKNOWN("firefightingLiftProvidedFlag missing (required when >18m)", [
      `maxStoreyAboveFRSAccessLevelM=${h}`
    ]);

  const failures: string[] = [];
  if (shaft === false) failures.push("firefightingShaftProvidedFlag=false");
  if (n < 1) failures.push(`numberOfFirefightingShafts=${n} (<1)`);
  if (lift === false) failures.push("firefightingLiftProvidedFlag=false");

  if (failures.length)
    return FAIL("Storey >18m above FRS access level: firefighting shaft(s) with lift not provided", [
      `maxStoreyAboveFRSAccessLevelM=${h}`,
      ...failures
    ]);

  return PASS("Storey >18m above FRS access level: firefighting shaft(s) with firefighting lift provided", [
    `maxStoreyAboveFRSAccessLevelM=${h}`,
    "firefightingShaftProvidedFlag=true",
    `numberOfFirefightingShafts=${n}`,
    "firefightingLiftProvidedFlag=true"
  ]);
