export const __PASS3_BATCH4_MARKER__ = true;


// ---- Batch 13: Multi-factor rules ----
export const eval_B1_STAIR_TRAVEL_DISTANCE_01: EvalFn = (facts, _rule) => {
  const h = (facts as any)?.storeys;
  const d = (facts as any)?.travelDistance;

  if (typeof h !== "number" || typeof d !== "number") {
    return UNKNOWN("Missing height or distance", ["storeys=missing", "travelDistance=missing"]);
  }

  if (h > 11 && d > 18) {
    return FAIL("Exceeds travel distance for >11m", [
      `storeys=${h}`,
      `travelDistance=${d}`,
    ]);
  }

  return PASS("Travel distance within limit", [`storeys=${h}`, `travelDistance=${d}`]);
};
